var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"주먹만으로 침식체들을 전부 해치우다니.","JPN":"拳だけで侵食体を全部やっつけるなんて。","ENG":"She defeated all those C.O.s with just her bare hands.","TWN":"竟然只用拳頭就把侵蝕體全都解決了。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"굉장하시네요, 파티마 씨.","JPN":"すごいですね、ファティマさん。","ENG":"That was amazing, Miss Fatima.","TWN":"法蒂瑪真是了不起……"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"별 말씀을. 브레히트 양의 공중 지원 덕분입니다.","JPN":"とんでもないです。ブレヒトさんの空中支援のおかげです。","ENG":"It was all thanks to your aerial support, Miss Brecht.","TWN":"哪裡的話，多虧了你的空中支援，布萊希特。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"하지만 침식체를 해치워도 침식파 반응은 좀처럼 약해지지 않는군요.","JPN":"ですが、侵食体をやっつけても侵食波の反応は弱くなりませんね。","ENG":"But no matter how many C.O.s we defeat, the Corruption ray response hasn't weakened at all.","TWN":"不過即使擊敗了侵蝕體，侵蝕波反應也依然沒有減弱。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식파의 원인이 되는 녀석은 따로 있는 것 같군.","JPN":"侵食波の原因になっているやつは他にいるようだ。","ENG":"It seems that there is something else causing the Corruption ray.","TWN":"看來有另一個傢伙在影響侵蝕波。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"고위 침식파 신호가 둘. 9시와 3시 방향에서 동시에 잡힙니다.","JPN":"高レベルの侵食波信号が2体。9時と3時の方角から同時に感知されます。","ENG":"There are two high-grade Corruption rays coming simultaneously from our 3 and 9 o'clock.","TWN":"捕捉到兩個高階侵蝕波訊號。分別在9點和3點鐘方向。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"둘이요? 그런 걸 동시에 상대하는 건 아무리 파티마 씨라도 무리지 않나요?","JPN":"2体？　それを同時に相手するのは、いくらファティマさんでも無理じゃないですか？","ENG":"Two of them? Won't that be too much for you to handle on your own, Miss Fatima?","TWN":"兩個嗎？即使是法蒂瑪同時對付兩個也太勉強了……？"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"둘 모두 그림자라면, 확실히 번거롭겠군요.","JPN":"両方ともシャドウなら、確かに面倒でしょう。","ENG":"If both are Shadows, then it will definitely be a challenge.","TWN":"如果兩個都是暗影的話，會很麻煩。"},"stage":{"bg":"COUNTERSIDE_BASE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"체르노보그.","JPN":"チェルノボーグ。","ENG":"Chernobog.","TWN":"申諾伯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"처리해.","JPN":"やれ。","ENG":"Take care of it.","TWN":"解決掉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"9시 방향 900m에 그림자로 추정되는 3종 침식체! 차원균열을 뚫고 이쪽으로 접근 중…!","JPN":"9時の方角、900mにシャドウと推定される第3種侵食体！　次元亀裂を貫いてこちらに接近中……！","ENG":"A Category 3 C.O. presumed to be a Shadow 900 m away at 9 o'clock! It's breaking through the dimensional rift and headed this way...!","TWN":"9點鐘方向900ｍ處，推測為3類侵蝕體的暗影！正穿過次元裂縫向這邊接近……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"하나는 아직 안 보여요! 저 녀석을 어떻게든 먼저 잡을 수만 있다면…!","JPN":"残り1体はまだ見えません！　あいつを何とか先に倒すことができたら……！","ENG":"I don't see the other one! If we can defeat that one first, then...!","TWN":"我沒有看到另一個！只要能先擊敗這一個的話……！"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"어…?","JPN":"え……？","ENG":"Huh...?","TWN":"呃……?"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"제가 뭘 보고 있는 거죠…? 침식체들이 서로 싸우다니.","JPN":"私、何を見てるんでしょう……？　侵食体同志で戦ってるなんて。","ENG":"What am I seeing...? The C.O.s are fighting each other.","TWN":"我看到了什麼……？侵蝕體自己打起來了……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저도 저런 광경은 처음 봅니다.","JPN":"私もこんな光景は初めてです。","ENG":"I've never seen this before as well.","TWN":"我也是第一次見到這種情況。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"게다가 저 전투의 양상은…","JPN":"それに、あの戦闘の様子は……","ENG":"And the battle...","TWN":"而且戰鬥局面是……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…뒤이어 나타난 인간형 그림자가 일방적으로 몰아붙이고 있군.","JPN":"……後から現われた人間型のシャドウが一方的に追いつめているな。","ENG":"...The Human type Shadow that appeared later is cornering the other like it's nothing.","TWN":"……侵蝕體被之後出現的人形暗影單方面壓制了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"적어도 3종은 돼 보였는데, 단숨에 해치웠어요.","JPN":"少なくとも第3種に見えたんですけど、一気にやっつけました。","ENG":"It looked to be at least a Category 3, but it was finished off so easily.","TWN":"侵蝕體至少有3類，但卻解決得很輕鬆……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SUMMON_UNION_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"이쪽을 보고 있습니다.","JPN":"こちらを見ています。","ENG":"It's looking this way.","TWN":"它在觀察我們。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"일반적인 그림자라면 카운터를 보고 당장 달려들 텐데, 이상할 정도로 침착하군요.","JPN":"一般的なシャドウならカウンターを見るなり飛びかかってくるはずですが、妙に落ち着いていますね。","ENG":"An ordinary Shadow would've already rushed toward us after seeing a Counter. But this one is strangely calm.","TWN":"如果是普通的暗影，看到制裁者會立刻撲上來，但它卻冷靜得不像話。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"…뭔가 더 오고 있어요.","JPN":"……何かがもっと来ます。","ENG":"...Something else is approaching as well.","TWN":"……還有什麼東西在靠近。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"이 소린…","JPN":"この音は……","ENG":"That sound...","TWN":"這聲音是……"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NEXT_NULL","text":{"KOREA":"헬리콥터?","JPN":"ヘリコプター？","ENG":"Is that a helicopter?","TWN":"直升機？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NEXT_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"체르노보그가 고위 침식체를 처리했다.","JPN":"チェルノボーグが高レベルの侵食体を処理した。","ENG":"Chernobog has taken care of the high-tier C.O.","TWN":"申諾伯已將高階侵蝕體消滅。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>방문객</color>의 생존을 확인. 신속히 주변 일대의 안전을 확보하도록. 이상.","JPN":"<color=#ffd34c>訪問者</color>の生存を確認。迅速に周辺一帯の安全を確保するように。以上。","ENG":"Confirmed the survival of the <color=#ffd34c>visitors</color>. Swiftly secure the perimeter. Over.","TWN":"確認到<color=#ffd34c>訪客</color>的存活。請迅速確保周邊區域的安全。完畢。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"바바 야가 편대로군. 북방합의체에서 보낸 건가?","JPN":"バーバ・ヤーガ編隊だな。北方合意体が送ってきたのか？","ENG":"It's the Baba Yaga squad. Are they from the Northern Union?","TWN":"他們是芭芭雅嘎小隊，是北方和議會派來的嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저 마크…","JPN":"あのマーク……","ENG":"That mark...","TWN":"那個標記……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"붉은 마녀단이군요.","JPN":"赤の魔女団ですね。","ENG":"It's the Red Witches.","TWN":"是紅魔女。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"펠릭스 직속 근위대입니다.","JPN":"フェリックスの直属親衛隊です。","ENG":"They are Felix's personal guards.","TWN":"他們是緋莉克絲的直屬近衛隊。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"펠릭스…? 그 사람이 왜 여기에…?","JPN":"フェリックス……？　どうしてあの人がここに……？","ENG":"Felix...? Why would she be here...?","TWN":"緋莉克絲……？那個人為什麼會在這裡……？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"군인들이 저흴 포위하는 것 같은데요? 지금이라도 도망쳐야 할까요?","JPN":"軍人たちが私たちを取り囲んでいるようですよ？　今からでも逃げるべきでしょうか？","ENG":"I think the soldiers are surrounding us. Should we try to make a run for it?","TWN":"我們好像被士兵包圍了？要嘗試逃跑嗎……？"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저들이 이미 상공을 봉쇄했습니다.","JPN":"あの者たちはすでに上空を封鎖しました。","ENG":"They've already blocked off the sky.","TWN":"天空已經被封鎖了。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"바바 야가가 나타났다는 건, 현실세계로 부상하는 통로도 막혔다는 뜻이죠.","JPN":"バーバ・ヤーガが現われたということは、ノーマルサイドに浮上する通路も塞がれたということです。","ENG":"With Baba Yaga here, it means that the passage to the Normalside has been blocked.","TWN":"而芭芭雅嘎的出現，就表示通往現實世界的通道也是如此。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…불길하네요.","JPN":"……嫌な予感がします。","ENG":"...This isn't good.","TWN":"……很不妙啊。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우릴 향해 미사일은 쏘지 않았잖나.","JPN":"私たちに向けてミサイルを撃ってこないではないか。","ENG":"They haven't fired any missiles at us.","TWN":"他們不是沒有向我們發射導彈嘛。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대화를 나눠볼 여지는 있단 뜻이지.","JPN":"会話をする余地はあるということさ。","ENG":"It could mean that there is still room to talk.","TWN":"意思是還有交談的餘地。"},"stage":{"bg":"COUNTERSIDE_BASE_NIGHT","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"마중이 늦어져서 미안.","JPN":"迎えが遅れてすまない。","ENG":"I'm sorry for being late.","TWN":"抱歉，我來遲了。"},"stage":{"bg":"BLACK","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"다른 처리할 업무가 좀 있었거든.","JPN":"他に処理すべき業務が少しあってな。","ENG":"I had some other matters to take care of first.","TWN":"有些其他的事務需要處理。"},"stage":{"bg":"BLACK","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"길을 잃은 것 같은데, 좀 도와줄까?","JPN":"道に迷っているようだが、手を貸そうか？","ENG":"You seem lost. Would you like some help?","TWN":"你們看起來迷路了，需要我幫忙嗎？"},"stage":{"bg":"MS_1301","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"북방합의체 참모총장, 펠릭스.","JPN":"北方合意体の総参謀長、フェリックス。","ENG":"The Northern Union's Chief of the General Staff, Felix.","TWN":"呵呵……北方和議會的參謀總長，緋莉克絲。"},"stage":{"bg":"MS_1301","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"조난 신호도 보내지 않았는데 우릴 찾아냈군.","JPN":"遭難信号を発していないのにも関わらず、私たちを見つけたんだな。","ENG":"We didn't even send a distress signal, and yet, you found us.","TWN":"我們沒有發出求救訊號，而你卻找到了我們。"},"stage":{"bg":"MS_1301","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"고등급 카운터의 존재는 그림자를 끌어들이지.","JPN":"高ランクカウンターの存在はシャドウをおびき寄せる。","ENG":"A high-grade Counter is bound to attract Shadows.","TWN":"高級制裁者的存在會吸引暗影。"},"stage":{"bg":"MS_1301","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"그리고 그림자를 추적하는 건 내 주력군의 특기니까.","JPN":"そしてシャドウの追跡は、私の主力軍が得意としてるからな。","ENG":"And tracking Shadows is my specialty.","TWN":"而追蹤暗影正是我軍主力的特長。"},"stage":{"bg":"MS_1301","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"어찌 됐건, 북방합의체 방문을 환영해.","JPN":"それはさておき、北方合意体への訪問を歓迎する。","ENG":"Anyway, welcome to the Northern Union.","TWN":"不管怎樣，歡迎訪問北方和議會。"},"stage":{"bg":"MS_1301","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_UNION_NULL_NULL","text":{"KOREA":"최고관리자 나리.","JPN":"最高管理者。","ENG":"Mr. Supreme Administrator.","TWN":"最高管理者。"},"stage":{"bg":"MS_1301","bgm":"THEMA_SA_COMMANDER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};